// src/PlumGame.js
import React, { useContext, useState, useRef, useEffect } from "react";
import { useNavigate } from "react-router-dom";
import { GameContext } from "./GameContext";
import { motion, AnimatePresence } from "framer-motion";
import { supabase } from "./supabaseClient"; // Подключение Supabase

// Импорт графики
import upgradesIcon from "./assets/icons/upgrades.png";
import shopIcon from "./assets/icons/shop.png";
import settingsIcon from "./assets/icons/settings.png";
import plumIcon from "./assets/icons/plum.png";
import plumCoin from "./assets/plumcoin.png";
import gp from "./assets/gp.png";
import rouletteIcon from "./assets/icons/Roulete.png";

//Импорт скинов кнопок
import mySticker from "./assets/mySticker.png";
import Straw from "./assets/Straw.png";
import Wooden from "./assets/Wooden.png";
import Stone from "./assets/Stone.png";
import Iron from "./assets/Iron.png";
import Bronza from "./assets/Bronza.png";
import Silver from "./assets/Silver.png";
import Gold from "./assets/Gold.png";
import Platinum from "./assets/Platinum.png";
import Diamond from "./assets/Diamond.png";
import Mythical from "./assets/Mythical.png";

// Импорт Audio
import clickSound from "./assets/audio/click.mp3";

const PlumGame = () => {
  const { state, dispatch } = useContext(GameContext);
  const navigate = useNavigate();

  // Данные пользователя и переключатель отображения полного ID
  const [userInfo, setUserInfo] = useState(null);
  const [showFullID, setShowFullID] = useState(false);
const [showIDModal, setShowIDModal] = useState(false);

  // Состояния для модального окна, эффектов и прочего
  const [showModal, setShowModal] = useState(false);
  const [isClosing, setIsClosing] = useState(false);
  const [floatingTexts, setFloatingTexts] = useState([]);
  const [isTapped, setIsTapped] = useState(false);
  const [scatteredPlums, setScatteredPlums] = useState([]);
  const prevLevelRef = useRef(state.level);
  const lastTapTimeRef = useRef(0);
  
  
  const getStickerByLevel = (level) => {
  switch (level) {
    case 10: return Mythical;
    case 9: return Diamond;
    case 8: return Platinum;
    case 7: return Gold;
    case 6: return Silver;
    case 5: return Bronza;
    case 4: return Iron;
    case 3: return Stone;
    case 2: return Wooden;
	case 1: return Straw;
    default: return Straw;
  }
};

const getLeagueName = (level) => {
  switch(level) {
    case 10: return "Mythical League";
    case 9: return "Diamond League";
    case 8: return "Platinum League";
    case 7: return "Gold League";
    case 6: return "Silver League";
    case 5: return "Bronza League";
    case 4: return "Iron League";
    case 3: return "Stone League";
    case 2: return "Wooden League";
    case 1: 
    default: return "Straw League";
  }
};


  const [stickerImage, setStickerImage] = useState(getStickerByLevel(state.level));
const [fade, setFade] = useState(false);

 // Достижение Ур.2 замена картинки
useEffect(() => {
  setFade(true); // начинаем исчезновение
  const timeout = setTimeout(() => {
    setStickerImage(getStickerByLevel(state.level)); // смена картинки
    setFade(false); // возвращаем прозрачность
  }, 200); // время затемнения

  return () => clearTimeout(timeout);
}, [state.level]);

  
  // Отключаем прокрутку страницы на время работы компонента
  useEffect(() => {
    const originalStyle = window.getComputedStyle(document.body).overflow;
    document.body.style.overflow = "hidden";
    return () => {
      document.body.style.overflow = originalStyle;
    };
  }, []);

  // Массив эмодзи для аватара
  const emojiOptions = ["😎", "🔥", "🎮", "🚀", "💎", "✨", "🎉"];
  const [randomEmoji, setRandomEmoji] = useState("");
  useEffect(() => {
    setRandomEmoji(
      emojiOptions[Math.floor(Math.random() * emojiOptions.length)]
    );
  }, []);

  // Модальное окно: показываем один раз
  useEffect(() => {
    if (!sessionStorage.getItem("plumGameModalShown")) {
      setShowModal(true);
      sessionStorage.setItem("plumGameModalShown", "true");
    }
    const disableZoom = (e) => {
      if (e.touches.length > 1) e.preventDefault();
    };
    document.addEventListener("touchstart", disableZoom, { passive: false });
    return () => {
      document.removeEventListener("touchstart", disableZoom);
    };
  }, []);

  // Функция закрытия модального окна (если понадобится)
  const handleCloseModal = () => {
    setIsClosing(true);
    setTimeout(() => {
      setShowModal(false);
      setIsClosing(false);
    }, 500);
  };

  // Загружаем данные пользователя из Supabase
  useEffect(() => {
    const fetchUserData = async () => {
      const { data: { session } } = await supabase.auth.getSession();
      if (session) {
        const userId = session.user.id;
        const { data, error } = await supabase
          .from("users")
          .select("username, user_id")
          .eq("user_id", userId)
          .single();
        if (data) {
          setUserInfo(data);
        }
      }
    };
    fetchUserData();
  }, []);

  // Обновление уровня, если он увеличился
  if (state.level > prevLevelRef.current) {
    prevLevelRef.current = state.level;
  }

  // Функция форматирования количества Plum
  const formatPlums = (num) => {
    if (num >= 1e12) return (num / 1e12).toFixed(2) + "T";
    if (num >= 1e9) return (num / 1e9).toFixed(2) + "B";
    if (num >= 1e6) return (num / 1e6).toFixed(2) + "M";
    if (num >= 1e3) return (num / 1e3).toFixed(2) + "K";
    return num.toString();
  };

  // Функция форматирования времени
  const formatTime = (ms) => {
    const totalSec = Math.floor(ms / 1000);
    const hrs = Math.floor(totalSec / 3600);
    const mins = Math.floor((totalSec % 3600) / 60);
    const secs = totalSec % 60;
    return `${hrs.toString().padStart(2, "0")}:${mins
      .toString()
      .padStart(2, "0")}:${secs.toString().padStart(2, "0")}`;
  };

  // Расчет прогресса для повышения уровня
  const levelThresholds = [  200, 250, 300, 350, 400, 450, 500, 550, 600, 650,
  12910, 16266, 20495, 25824, 32539, 40999, 51658, 65089, 82012, 103336,
  130203, 164056, 206710, 260455, 328173, 413498, 521008, 656470, 827152, 1042211,
  1313186, 1654615, 2084814, 2626866, 3309851, 4170413, 5254720, 6620947, 8342394, 10511416,
  13244384, 16687924, 21026785, 26493749, 33382123, 42061475, 52997459, 66776798, 84138765, 106014844,
  133578704, 168309167, 212069550, 267207634, 336681618, 424218839, 534515737, 673489829, 848597184, 1069232452,
  1347232890, 1697513441, 2138866936, 2694972339, 3395665148, 4278538086, 5390957989, 6792607066, 8558684903, 10783942977,
  13587768151, 17120587871, 21571940717, 27180645304, 34247613083, 43151992484, 54371510530, 68508103268, 86320210117, 108763464748,
  137041965582, 172672876633, 217567824558, 274135458943, 345410678268, 435217454618, 548373992818, 690951230951, 870598550998, 1096954174258,
  1382162259565, 1741524447051, 2194320803285, 2764844212139, 3483703707295, 4389466671192, 5530728005702, 6968717287184, 8780583781852, 11063535565133];
  const nextThreshold =
    state.level <= levelThresholds.length ? levelThresholds[state.level - 1] : null;
  const progressPercent = nextThreshold
    ? Math.min(100, (state.plums / nextThreshold) * 100)
    : 100;

  // Функция тактильной отдачи
  const triggerHaptic = () => {
    if (typeof navigator.vibrate === "function") {
      navigator.vibrate(100);
    } else if (
      window.TapticEngine &&
      typeof window.TapticEngine.impact === "function"
    ) {
      window.TapticEngine.impact({ style: "medium" });
    }
  };

  // Проверка прозрачности пикселя изображения
  const isPixelTransparent = (img, x, y) => {
    const canvas = document.createElement("canvas");
    canvas.width = img.naturalWidth;
    canvas.height = img.naturalHeight;
    const ctx = canvas.getContext("2d");
    ctx.drawImage(img, 0, 0);
    const rect = img.getBoundingClientRect();
    const scaleX = img.naturalWidth / rect.width;
    const scaleY = img.naturalHeight / rect.height;
    const localX = (x - rect.left) * scaleX;
    const localY = (y - rect.top) * scaleY;
    const pixel = ctx.getImageData(localX, localY, 1, 1).data;
    return pixel[3] === 0;
  };

  // Обработчик нажатия (тап)
  const handleTap = (e) => {
    if (e && e.preventDefault) e.preventDefault();
    const now = Date.now();
    if (now - lastTapTimeRef.current < 100) return;
    lastTapTimeRef.current = now;
    let multiplier = 1;
    let clickX, clickY;
    if (e.touches && e.touches.length > 0) {
      multiplier = Math.min(e.touches.length, 5);
      clickX = e.touches[0].clientX;
      clickY = e.touches[0].clientY;
    } else {
      clickX = e.clientX;
      clickY = e.clientY;
    }
    const sticker = document.getElementById("mySticker");
    let targetElement = sticker || e.target;
    const rect = targetElement.getBoundingClientRect();
    if (
      clickX < rect.left ||
      clickX > rect.right ||
      clickY < rect.top ||
      clickY > rect.bottom
    )
      return;
    if (targetElement.tagName === "IMG") {
      if (isPixelTransparent(targetElement, clickX, clickY)) return;
    }
    const localX = clickX - rect.left;
    const localY = clickY - rect.top;
    const centerX = rect.width / 2;
    const centerY = rect.height / 2;
    const radius = rect.width / 2.2;
    const distance = Math.sqrt(
      Math.pow(localX - centerX, 2) + Math.pow(localY - centerY, 2)
    );
    if (distance > radius) return;
    if (localStorage.getItem("soundEnabled") === "true") {
      new Audio(clickSound).play();
    }
    if (localStorage.getItem("vibrationEnabled") === "true") {
      triggerHaptic();
    }
    dispatch({ type: "ADD_PLUM", payload: multiplier });
    setIsTapped(true);
    setFloatingTexts((prev) => [
      ...prev,
      ...Array.from({ length: multiplier }, () => {
        const angle = Math.random() * 2 * Math.PI;
        const offsetDistance = 50 + Math.random() * 30;
        return {
          id: Math.random(),
          startX: localX,
          startY: localY,
          offsetX: offsetDistance * Math.cos(angle),
          offsetY: offsetDistance * Math.sin(angle),
          value: multiplier,
        };
      }),
    ]);
    setScatteredPlums((prev) => [
      ...prev,
      ...Array.from({ length: 3 * multiplier }, () => ({
        id: Math.random(),
        startX: localX,
        startY: localY,
        offsetX: (Math.random() - 0.8) * 300,
        offsetY: (Math.random() - 0.8) * 300,
      })),
    ]);
    setTimeout(() => {
      setScatteredPlums((prev) => prev.slice(multiplier * 3));
      setFloatingTexts((prev) => prev.slice(multiplier));
    }, 2000);
  };

  const currentTime = Date.now();
  let rouletteButtonText = "";
  let rouletteDisabled = false;
  if (state.plums < 200) {
    rouletteButtonText = "Недостаточно Plum";
    rouletteDisabled = true;
  } else if (state.rouletteSpinsToday >= 3) {
    rouletteButtonText = "Попыток 0";
    rouletteDisabled = true;
  } else if (
    state.lastRouletteSpin &&
    currentTime - state.lastRouletteSpin < 10800000
  ) {
    const remainingMs = 10800000 - (currentTime - state.lastRouletteSpin);
    rouletteButtonText = `Подождите ${formatTime(remainingMs)}`;
    rouletteDisabled = true;
  } else {
    rouletteButtonText = "Крутить";
    rouletteDisabled = false;
  }

  const handleRouletteIconClick = () => {
    navigate("/upgrades", { state: { scrollTo: "roulette" } });
  };

  return (
    <div
      onDoubleClick={(e) => e.preventDefault()}
      className="select-none flex flex-col min-h-screen text-white relative overflow-hidden bg-cover bg-center"
      style={{
        backgroundImage: `url(${process.env.PUBLIC_URL + "/assets/gameBackground.jpg"})`,
        touchAction: "manipulation",
      }}
    >
      {/* Стильная карточка пользователя */}
{userInfo && (
  <>
    {/* 🪙 Gold Coin User Badge */}
<div
  onClick={() => setShowIDModal(true)}
  className="cursor-pointer absolute left-6 z-50 group flex items-center gap-3 px-4 py-2 w-40 h-18 rounded-2xl border border-yellow-300 backdrop-blur-sm transition-transform duration-500 hover:rotate-[2deg] hover:scale-105"
  style={{
    top: "20px", // регулирует позицию по высоте
    background: `
      radial-gradient(circle at 30% 30%, rgba(255, 255, 255, 0.25), transparent 50%),
      linear-gradient(135deg, #fff7d6 0%, #f9c74f 20%, #f8961e 40%, #f9844a 60%, #f9c74f 80%, #fff7d6 100%)
    `,
    backgroundSize: "200% 200%",
    animation: "slowGoldPulse 8s ease-in-out infinite",
    boxShadow: "0 3px 12px rgba(249, 199, 79, 0.35), inset 0 1px 1px rgba(255,255,255,0.5)",
    perspective: "1200px",
    transformStyle: "preserve-3d",
  }}
>
  {/* Аватар */}
  <div className="w-10 h-10 rounded-full bg-gradient-to-br from-yellow-100 to-yellow-300 shadow-inner flex items-center justify-center text-xl border border-yellow-400">
    <span>{randomEmoji}</span>
  </div>

  {/* Инфо и GP */}
  <div className="flex flex-col justify-center">
    <p className="text-[13px] text-yellow-50 font-bold tracking-wide drop-shadow-[0_1px_1px_rgba(0,0,0,0.4)]">
      Имя: <b>{userInfo.username}</b>
    </p>

    <span className="text-[7px] text-yellow-100 opacity-70 uppercase tracking-wider">
      <b>{getLeagueName(state.level)}</b> {/* <-- Здесь используем state.level */}
    </span>

    <span className="text-yellow-800 font-semibold text-sm mt-1 drop-shadow-[0_1px_1px_rgba(255,255,255,0.5)]">
      {formatPlums(state.gp)} GP
    </span>
  </div>
</div>







    {/* 💳 Gold Modal ID Window */}
    {showIDModal && (
      <div
        className="fixed inset-0 bg-black bg-opacity-70 backdrop-blur-sm flex items-center justify-center z-50"
        style={{ perspective: "1200px" }}
        onClick={() => setShowIDModal(false)}
      >
        <div
          className="bg-gradient-to-br from-yellow-100 via-yellow-200 to-orange-100 p-6 rounded-2xl shadow-[0_8px_30px_rgba(255,215,0,0.35)] w-80 transform transition-transform duration-500 hover:rotate-x-3 hover:rotate-y-1 border-[1.5px] border-yellow-300 relative"
          onClick={(e) => e.stopPropagation()}
        >
          <h3 className="text-2xl font-extrabold text-yellow-900 mb-4 drop-shadow-sm">🪪 User ID</h3>

          <div className="relative group">
            <p
              className="text-yellow-800 text-sm font-mono break-words border border-yellow-300 bg-yellow-50/70 rounded p-3 shadow-inner select-text"
              id="user-id-text"
            >
              {userInfo.user_id}
            </p>
            <button
              onClick={() => {
                navigator.clipboard.writeText(userInfo.user_id);
                const copyBtn = document.getElementById("copied-label");
                if (copyBtn) {
                  copyBtn.style.opacity = "1";
                  setTimeout(() => (copyBtn.style.opacity = "0"), 1500);
                }
              }}
              className="absolute top-9 right-2 text-yellow-700 hover:text-yellow-900 transition text-xs bg-yellow-100 px-2 py-1 rounded shadow border border-yellow-300"
            >
              Копировать
            </button>
            <span
              id="copied-label"
              className="absolute -bottom-4 right-2 text-green-600 text-xs transition-opacity duration-300 opacity-0"
            >
              Скопировано!
            </span>
          </div>

          <button
            onClick={() => setShowIDModal(false)}
            className="mt-5 w-full py-2 bg-gradient-to-r from-yellow-500 to-orange-400 text-yellow-50 font-bold rounded-full hover:scale-105 active:scale-95 transition-all duration-200 shadow-md border border-yellow-200"
          >
            Закрыть
          </button>
        </div>
      </div>
    )}
  </>
)}
{/* Блок рулетки */}
{!rouletteDisabled && (
  <div className="absolute top-60 right-10 z-10">
    <div
      onClick={handleRouletteIconClick}
      className="relative flex items-center justify-center p-2 cursor-pointer transform hover:scale-110 transition duration-300 ease-in-out bg-white bg-opacity-10 rounded-full shadow-md"
      style={{ backdropFilter: "blur(8px)" }}
    >
      <img
        src={rouletteIcon}
        alt="Roulette Icon"
        className="w-10 h-10 animate-spin"
      />
      <div className="absolute top-0 right-0 w-3 h-3 bg-red-600 rounded-full animate-pulse" />
    </div>
  </div>
)}
      {/* Модальное окно приветствия */}
      {showModal && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black bg-opacity-70">
          <div
            className={`relative bg-gradient-to-br from-purple-900 to-pink-700 rounded-xl p-8 w-11/12 max-w-md shadow-2xl ${
              isClosing ? "animate-pop-out" : "animate-pop"
            }`}
          >
            <button
              onClick={handleCloseModal}
              className="absolute top-3 right-3 text-red-400 text-3xl font-bold hover:text-red-600 transition"
              aria-label="Закрыть"
            >
              &times;
            </button>
            <h2 className="text-3xl sm:text-4xl font-extrabold mb-4 text-yellow-300 drop-shadow-md">
              Описание игры Plums
            </h2>
            <p className="text-md sm:text-lg text-white">
              Добро пожаловать в Plum Clicker! Нажимайте на главный объект, чтобы собирать сочные плумы, прокачивай уровень и получай новые скины... Скоро будут добавлены соревнования против других игроков, будет возможность выйграть реальные деньги!
            </p>
          </div>
        </div>
      )}
	  
	  

      {/* Декоративные элементы */}
      <div className="absolute inset-0 pointer-events-none z-0 overflow-hidden">
  {Array.from({ length: 50 }).map((_, index) => {
    const left = Math.random() * 100;
    const height = 20 + Math.random() * 40; // длина капли
    const duration = (Math.random() * 1 + 1.5).toFixed(2); // 1.5–2.5 сек
    const delay = (Math.random() * 2).toFixed(2); // 0–2 сек
    const opacity = (Math.random() * 0.3 + 0.2).toFixed(2); // 0.2–0.5

    return (
      <div
        key={index}
        className="absolute w-px bg-white animate-raindrop"
        style={{
          left: `${left}%`,
          height: `${height}px`,
          opacity,
          animationDuration: `${duration}s`,
          animationDelay: `${delay}s`,
        }}
      />
    );
  })}
</div>
      
      {/* Основной контент */}
      <div className="relative z-10 container mx-auto max-w-3xl p-6">
        {/* Блок с уровнем и балансом */}
<div className="flex flex-col items-end mb-4 mt-3" style={{ perspective: 1500 }}>
  {/* 🏅 Уровень */}
  <div
    className="w-8 h-10 flex items-center gap-4 px-2 py-2 w-fit rounded-full border-[1.5px] border-purple-200 shadow-[0_4px_20px_rgba(255,215,0,0.4)] backdrop-blur-sm bg-gradient-to-br from-purple-600 via-purple-600 to-purple-300 transition-transform duration-500 hover:rotate-[2deg] hover:scale-105"
    style={{
      backgroundSize: "300% 300%",
      animation: "goldShimmer 8s ease-in-out infinite",
      transformStyle: "preserve-3d",
    }}
  >
    <div
      className="w-8 h-8 rounded-full bg-gradient-to-br from-yellow-100 to-orange-300 shadow-inner flex items-center justify-center text-sm font-bold text-yellow-900 border border-yellow-400"
      style={{
        boxShadow: "inset 0 1px 2px rgba(255,255,255,0.6), 0 2px 4px rgba(0,0,0,0.2)",
      }}
    >
      Ур.
    </div>
    <div className="flex flex-col justify-center pr-1">
      <motion.span
        key={state.level}
        initial={{ opacity: 0, y: -10, scale: 0.95 }}
        animate={{ opacity: 1, y: 0, scale: 1 }}
        exit={{ opacity: 0, y: 10, scale: 0.95 }}
        transition={{ type: "spring", stiffness: 300, damping: 20 }}
        className="text-yellow-50 text-1g font-extrabold drop-shadow-[0_3px_3px_rgba(0,0,0,0.6)]"
      >
        {state.level}
      </motion.span>
    </div>
  </div>

  {/* 💰 PlumCoin */}
  <div
    className="mt-1 flex items-center gap-3 px-3 py-0 w-fit rounded-full border-[1.5px] border-yellow-200 shadow-[0_4px_12px_rgba(255,215,0,0.4)] backdrop-blur-sm bg-gradient-to-br from-orange-200 via-orange-400 to-orange-300 transition-transform duration-6 hover:rotate-[5deg] hover:scale-105"
    style={{
      backgroundSize: "300% 300%",
      animation: "goldShimmer 8s ease-in-out infinite",
      transformStyle: "preserve-3d",
    }}
  >
    <img src={plumCoin} alt="Plum Coin" className="w-8 h-8" />
    <span className="text-yellow-50 text-lg font-mono font-bold tracking-wide drop-shadow-[0_1px_1px_rgba(0,0,0,0.4)]">
      {formatPlums(state.plums)} PC
    </span>
  </div>
</div>

{/* Блок статусбара) */}
        {nextThreshold ? (
          <div className="mt-2">
            <div className="relative w-full h-8 rounded-full bg-gray-900 shadow-xl overflow-hidden">
              <div className="absolute inset-0 blur-lg bg-gradient-to-r from-cyan-400 to-purple-600 opacity-50"></div>
              <div
                className="h-8 rounded-full bg-gradient-to-r from-cyan-400 to-purple-600 transition-all duration-700"
                style={{ width: `${progressPercent}%` }}
              ></div>
              <p className="absolute inset-0 flex items-center justify-center text-white font-bold text-lg drop-shadow-lg">
                {formatPlums(state.plums)} / {formatPlums(nextThreshold)}
              </p>
            </div>
			
          </div>
		  
        ) : (
          <div className="mt-6">
            <p className="text-xl text-white text-center font-bold animate-pulse">
              Максимальный уровень достигнут! 🚀
            </p>
			
          </div>
		  
        )}

        {/* Блок с основным игровым объектом, эффектами нажатия и плавающими подписями */}
        <div className="flex flex-1 items-center justify-center mt-20 relative">
          <button
  onClick={handleTap}
  className="relative focus:outline-none"
>
            {isTapped && (
              <div className="absolute inset-0 flex items-center justify-center">
                <div className="w-full h-full bg-purple-300 opacity-70 rounded-full animate-press"></div>
              </div>
            )}
            {scatteredPlums.map((p) => (
              <img
                key={p.id}
                src={plumIcon}
                alt="Scattered Plum"
                className="absolute w-8 h-8 opacity-80 animate-scatter"
                style={{
                  left: "50%",
                  top: "50%",
                  "--offset-x": `${p.offsetX}px`,
                  "--offset-y": `${p.offsetY}px`,
                }}
              />
            ))}
            
            {/* Контейнер с изображением и плавающими подписями */}
            <div className="relative w-64 h-64">
              {floatingTexts.map((t) => (
                <span
                  key={t.id}
                  className="absolute text-2xl font-extrabold text-yellow-400 animate-float"
                  style={{
                    left: `${t.startX}px`,
                    top: `${t.startY}px`,
                    "--final-x": `${t.offsetX}px`,
                    "--final-y": `${t.offsetY}px`
                  }}
                >
                  +{t.value}
                </span>
              ))}
              <img
  id="mySticker"
  src={stickerImage}
  alt="Plum"
  className={`w-64 h-64 rounded-full object-contain transform transition duration-300 ease-in-out cursor-pointer hover:scale-110 active:scale-95 ${
    fade ? "opacity-0" : "opacity-100"
  }`}
/>


            </div>
          </button>
        </div>
      </div>

      {/* Нижнее меню в игровом стиле */}
<nav className="fixed bottom-11 left-0 right-0 flex justify-center gap-5 z-50">
  {[
    { icon: upgradesIcon, alt: "Улучшения", route: "/upgrades" },
    { icon: shopIcon, alt: "Магазин", route: "/shop" },
    { icon: settingsIcon, alt: "Настройки", route: "/settings" },
  ].map(({ icon, alt, route }, index) => (
    <button
      key={index}
      onClick={() => navigate(route)}
      className="relative group p-4 rounded-2xl bg-gradient-to-br from-purple-600 via-pink-500 to-yellow-400 shadow-lg transition-transform duration-300 hover:scale-110"
    >
      <div className="absolute inset-0 rounded-2xl bg-black bg-opacity-30 backdrop-blur-md group-hover:bg-opacity-20 transition duration-300"></div>
      <img src={icon} alt={alt} className="relative z-10 w-10 h-10 sm:w-12 sm:h-12" />
      <span className="absolute -bottom-5 left-1/2 transform -translate-x-1/2 text-xs text-white font-semibold tracking-wide drop-shadow-md opacity-80">
        {alt}
      </span>
    </button>
  ))}
</nav>
    </div>
  );
};

export default PlumGame;
