// src/Upgrades.js
import React, { useContext, useState, useEffect } from "react";
import { GameContext } from "./GameContext";
import { useNavigate } from "react-router-dom";

// Иконки
import AutoTapIcon from "./assets/icons/autotap.png";
import CriticalDamageIcon from "./assets/icons/CriticalDamage.png";
import RouleteIcon from "./assets/icons/Roulete.png";
import SpinIcon from "./assets/icons/spin.png";
import upgradesIcon from "./assets/icons/click.png";
import shopIcon from "./assets/icons/shop.png";
import settingsIcon from "./assets/icons/settings.png";
import fingerUpgradeIcon from "./assets/icons/finger.png";

const Upgrades = () => {
  const { state, dispatch } = useContext(GameContext);
  const navigate = useNavigate();

  const [countdown, setCountdown] = useState(0);
  const [isRouletteOpen, setIsRouletteOpen] = useState(false);

  const formatTime = (ms) => {
    const totalSec = Math.floor(ms / 1000);
    const hours = Math.floor(totalSec / 3600);
    const minutes = Math.floor((totalSec % 3600) / 60);
    const seconds = totalSec % 60;
    return `${hours.toString().padStart(2, "0")}:${minutes
      .toString()
      .padStart(2, "0")}:${seconds.toString().padStart(2, "0")}`;
  };

  useEffect(() => {
    const tick = () => {
      if (state.lastRouletteSpin) {
        const cooldown = 10800000;
        const elapsed = Date.now() - state.lastRouletteSpin;
        const remaining = cooldown - elapsed;
        setCountdown(remaining > 0 ? remaining : 0);
      } else {
        setCountdown(0);
      }
    };
    tick();
    const interval = setInterval(tick, 1000);
    return () => clearInterval(interval);
  }, [state.lastRouletteSpin]);

  const buyAutoTap = () => {
    if (state.plums >= state.autoTapCost) {
      dispatch({ type: "BUY_AUTO_TAP", payload: { cost: state.autoTapCost } });
    } else {
      alert("Не хватает Plum для покупки!");
    }
  };

  const handleBuyCritical = () => {
    dispatch({ type: "BUY_CRITICAL_UPGRADE" });
  };

  const handleStartRoulette = () => {
    dispatch({ type: "START_ROULETTE" });
    setTimeout(() => {
      const bonus = Math.floor(Math.random() * (2000 - 50 + 1)) + 50;
      dispatch({ type: "FINISH_ROULETTE", payload: { bonus } });
    }, 3000);
  };

  const handleClearRoulette = () => {
    dispatch({ type: "CLEAR_ROULETTE" });
    setIsRouletteOpen(false);
  };

  const buyFingerUpgrade = () => {
    if (!state.fingerUpgradePurchased && state.plums >= 1000) {
      dispatch({ type: "BUY_FINGER_UPGRADE", payload: { cost: 1000 } });
    } else if (state.fingerUpgradePurchased) {
      alert("Апгрейд уже куплен!");
    } else {
      alert("Не хватает Plum для покупки апгрейда!");
    }
  };

  let rouletteButtonText = "";
  let rouletteDisabled = false;
  if (state.plums < 200) {
    rouletteButtonText = "Недостаточно Plum";
    rouletteDisabled = true;
  } else if (state.rouletteSpinsToday >= 3) {
    rouletteButtonText = "Максимум 3 раза в день";
    rouletteDisabled = true;
  } else if (countdown > 0) {
    rouletteButtonText = `Подождите ${formatTime(countdown)}`;
    rouletteDisabled = true;
  } else {
    rouletteButtonText = "Крутануть Рулетку";
    rouletteDisabled = false;
  }

  return (
    <div className="min-h-screen bg-gradient-to-br from-blue-500 via-purple-500 to-pink-500 text-white p-4">
      <div className="container mx-auto max-w-4xl">
        <h1 className="text-4xl font-extrabold text-center mb-6 drop-shadow-lg">Улучшения</h1>

        {/* Грид с двумя столбцами */}
        <div className="grid grid-cols-2 gap-4">
          {/* Авто-Тап */}
          <UpgradeCard
            icon={AutoTapIcon}
            title="Авто-Тап"
            info={[
              `Количество: ${state.autoPlums}`,
              `Стоимость: ${state.autoTapCost} Plum`,
            ]}
            onClick={buyAutoTap}
            buttonText="Купить"
            buttonColor="bg-purple-600 hover:bg-purple-700"
          />

          {/* Критический Тап */}
          <UpgradeCard
            icon={CriticalDamageIcon}
            title="Критический Тап"
            info={[
              `Шанс: ${state.criticalChance}%`,
              `Множитель: ${state.criticalMultiplier}x`,
              `Стоимость: ${state.criticalUpgradeCost} Plum`,
            ]}
            onClick={handleBuyCritical}
            buttonText="Улучшить"
            buttonColor="bg-blue-600 hover:bg-blue-700"
          />

          {/* Рулетка */}
          <UpgradeCard
            icon={RouleteIcon}
            title="Рулетка"
            info={["Стоимость прокрута: 200 Plum"]}
            onClick={() => setIsRouletteOpen(true)}
            buttonText={rouletteButtonText}
            buttonColor="bg-red-600 hover:bg-red-700"
            disabled={rouletteDisabled}
          />

          {/* Апгрейд 5 пальцев */}
          <div className="bg-white bg-opacity-20 rounded-lg p-3 shadow-md text-sm">
  <div className="flex items-center mb-2">
    <img src={fingerUpgradeIcon} alt="5 пальцев" className="w-8 h-8 mr-2" />
    <h2 className="text-base font-semibold">Апгрейд 5 пальцев</h2>
  </div>
  <p className="text-xs mb-1">При касании 1–5 пальцами начисление x1–x5</p>
  <p className="text-xs mb-2">Стоимость: <b>1000 Plum</b></p>
  {!state.fingerUpgradePurchased ? (
    <button
      onClick={buyFingerUpgrade}
      className="w-full py-1 rounded-md bg-teal-600 text-sm font-semibold hover:bg-teal-700"
    >
      Купить
    </button>
  ) : (
    <span className="text-green-400 font-semibold text-sm">Апгрейд куплен!</span>
  )}
</div>
        </div>

        {/* Модальное окно Рулетки в игровом стиле */}
        {isRouletteOpen && (
          <div className="fixed inset-0 bg-black bg-opacity-70 flex justify-center items-center z-50">
            <div className="bg-gray-800 text-white rounded-xl p-6 w-full max-w-xs border-4 border-yellow-500 shadow-2xl relative">
              <h2 className="text-2xl font-bold text-center mb-4">Рулетка</h2>
              {state.rouletteSpinning ? (
                <div className="flex flex-col items-center">
                  <img src={SpinIcon} alt="spin" className="w-12 h-12 animate-spin" />
                  <p className="mt-2 text-lg">Вращается...</p>
                </div>
              ) : state.rouletteResult !== null ? (
                <div className="text-center">
                  <p className="text-lg mb-4">
                    Вы выиграли: <b>{state.rouletteResult} Plum</b>!
                  </p>
                  <button
                    onClick={handleClearRoulette}
                    className="w-full py-1 rounded-md bg-green-600 text-white text-base font-bold hover:bg-green-700"
                  >
                    Принять
                  </button>
                </div>
              ) : (
                <button
                  onClick={handleStartRoulette}
                  className="w-full py-2 rounded-md bg-red-600 text-white text-xl font-bold hover:bg-red-700"
                >
                  Крутануть
                </button>
              )}
              <button
                onClick={() => setIsRouletteOpen(false)}
                className="absolute top-2 right-3 text-2xl text-gray-300 hover:text-red-400"
              >
                &times;
              </button>
            </div>
          </div>
        )}

        {/* Навигация */}
        <nav className="flex justify-around mt-6">
          <NavButton icon={upgradesIcon} label="Тапать" onClick={() => navigate("/")} />
          
        </nav>
      </div>
    </div>
  );
};

// Компонент карточки улучшения
const UpgradeCard = ({ icon, title, info, onClick, buttonText, buttonColor, disabled }) => (
  <div className="bg-white bg-opacity-20 rounded-lg p-3 shadow-md text-sm">
    <div className="flex items-center mb-2">
      <img src={icon} alt={title} className="w-8 h-8 mr-2" />
      <h2 className="text-base font-semibold">{title}</h2>
    </div>
    {info.map((line, i) => (
      <p className="text-xs mb-1" key={i}>
        {line}
      </p>
    ))}
    <button
      onClick={onClick}
      className={`w-full py-1 mt-1 rounded-md text-sm font-semibold transition-colors ${buttonColor}`}
      disabled={disabled}
    >
      {buttonText}
    </button>
  </div>
);

// Кнопка навигации
const NavButton = ({ icon, label, onClick }) => (
  <button onClick={onClick} className="flex flex-col items-center transform transition hover:scale-105">
    <img src={icon} alt={label} className="w-8 h-8 mb-1" />
    <span className="text-sm font-bold">{label}</span>
  </button>
);

export default Upgrades;
