// src/Auth.js
import React, { useState } from "react";
import { supabase } from "./supabaseClient";

const Auth = () => {
  const [isSignUp, setIsSignUp] = useState(false);
  const [loginInput, setLoginInput] = useState(""); // Email или Username
  const [email, setEmail] = useState("");
  const [username, setUsername] = useState("");
  const [password, setPassword] = useState("");
  const [confirmPassword, setConfirmPassword] = useState(""); // Подтверждение пароля
  const [message, setMessage] = useState("");

  // Регистрация пользователя
  const handleSignUp = async () => {
    if (password !== confirmPassword) {
      setMessage("Ошибка: Пароли не совпадают.");
      return;
    }

    const { data, error } = await supabase.auth.signUp({ email, password });

    if (error) {
      setMessage(`Ошибка: ${error.message}`);
    } else {
      setMessage("Регистрация успешна! Проверьте почту для подтверждения.");

      // Проверяем, есть ли объект пользователя
      if (data && data.user) {
        const { dbError } = await supabase
          .from("users")
          .insert([{ user_id: data.user.id, username, email }]);

        if (dbError) {
          setMessage(`Ошибка при сохранении имени пользователя: ${dbError.message}`);
        }
      } else {
        setMessage("Ошибка: Пользователь не был создан.");
      }
    }
  };

  // Авторизация пользователя (по username или email)
  const handleSignIn = async () => {
    let loginField = "email"; // По умолчанию вход через email

    // Если ввели не email, ищем username в таблице
    if (!loginInput.includes("@")) {
      const { data, error } = await supabase
        .from("users")
        .select("email")
        .eq("username", loginInput)
        .single();

      if (error || !data) {
        setMessage("Ошибка: Имя пользователя не найдено.");
        return;
      }

      loginField = data.email;
    } else {
      loginField = loginInput;
    }

    // Вход в систему
    const { error } = await supabase.auth.signInWithPassword({
      email: loginField,
      password,
    });

    if (error) {
      setMessage(`Ошибка: ${error.message}`);
    } else {
      setMessage("Вы успешно вошли!");
    }
  };

  return (
    <div className="flex flex-col items-center justify-center h-screen bg-gradient-to-r from-pink-500 via-purple-500 to-indigo-500">
      <div className="bg-black bg-opacity-60 p-8 rounded-lg shadow-xl w-80">
        <h2 className="text-3xl font-bold mb-6 text-center">
          {isSignUp ? "Регистрация Plum" : "Вход в Plum"}
        </h2>

        {/* Авторизация: сначала ввод Email или Username, затем пароль */}
        {!isSignUp && (
          <>
            <input
              type="text"
              placeholder="Email или Имя пользователя"
              value={loginInput}
              onChange={(e) => setLoginInput(e.target.value)}
              className="p-3 w-full mb-4 rounded bg-gray-800 text-white placeholder-gray-400 focus:outline-none focus:ring-2 focus:ring-purple-500"
            />
            <input
              type="password"
              placeholder="Пароль"
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              className="p-3 w-full mb-4 rounded bg-gray-800 text-white placeholder-gray-400 focus:outline-none focus:ring-2 focus:ring-purple-500"
            />
          </>
        )}

        {/* Регистрация: ввод Email, Username, затем пароль */}
        {isSignUp && (
          <>
            <input
              type="text"
              placeholder="Имя пользователя"
              value={username}
              onChange={(e) => setUsername(e.target.value)}
              className="p-3 w-full mb-4 rounded bg-gray-800 text-white placeholder-gray-400 focus:outline-none focus:ring-2 focus:ring-purple-500"
            />
            <input
              type="email"
              placeholder="Email"
              value={email}
              onChange={(e) => setEmail(e.target.value)}
              className="p-3 w-full mb-4 rounded bg-gray-800 text-white placeholder-gray-400 focus:outline-none focus:ring-2 focus:ring-purple-500"
            />
            <input
              type="password"
              placeholder="Пароль"
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              className="p-3 w-full mb-4 rounded bg-gray-800 text-white placeholder-gray-400 focus:outline-none focus:ring-2 focus:ring-purple-500"
            />
            <input
              type="password"
              placeholder="Подтвердите пароль"
              value={confirmPassword}
              onChange={(e) => setConfirmPassword(e.target.value)}
              className="p-3 w-full mb-6 rounded bg-gray-800 text-white placeholder-gray-400 focus:outline-none focus:ring-2 focus:ring-purple-500"
            />
          </>
        )}

        <div className="flex gap-2 justify-center">
          {isSignUp ? (
            <button
              onClick={handleSignUp}
              className="bg-green-600 hover:bg-green-700 px-4 py-2 rounded font-semibold"
            >
              Зарегистрироваться
            </button>
          ) : (
            <button
              onClick={handleSignIn}
              className="bg-blue-600 hover:bg-blue-700 px-4 py-2 rounded font-semibold"
            >
              Войти
            </button>
          )}
        </div>

        {message && <p className="mt-4 text-center text-sm">{message}</p>}

        <div className="mt-6 text-center">
          <span
            className="cursor-pointer underline hover:text-gray-300"
            onClick={() => setIsSignUp(!isSignUp)}
          >
            {isSignUp
              ? "Уже есть аккаунт? Войти"
              : "Нет аккаунта? Зарегистрироваться"}
          </span>
        </div>
      </div>
    </div>
  );
};

export default Auth;
