import React, { useReducer, useEffect } from "react";
import { GameContext } from "./GameContext";

const getLocalStorageNumber = (key, defaultValue) => {
  const storedValue = localStorage.getItem(key);
  const numberValue = Number(storedValue);
  return storedValue !== null && storedValue !== "" && !isNaN(numberValue)
    ? numberValue
    : defaultValue;
};

const getLocalStorageBoolean = (key, defaultValue) => {
  const storedValue = localStorage.getItem(key);
  if (storedValue === "true") return true;
  if (storedValue === "false") return false;
  return defaultValue;
};

const initialState = {
  plums: getLocalStorageNumber("plums", 0),
  gp: getLocalStorageNumber("gp", 0),
  autoPlums: getLocalStorageNumber("autoPlums", 0),
  level: getLocalStorageNumber("level", 1),
  tapMultiplier: getLocalStorageNumber("tapMultiplier", 1),
  autoTapCost: getLocalStorageNumber("autoTapCost", 50),
  criticalChance: getLocalStorageNumber("criticalChance", 10),
  criticalMultiplier: getLocalStorageNumber("criticalMultiplier", 2),
  criticalUpgradeCost: getLocalStorageNumber("criticalUpgradeCost", 100),
  fingerUpgradePurchased: getLocalStorageBoolean("fingerUpgradePurchased", false),
  rouletteSpinning: false,
  rouletteResult: null,
  rouletteSpinsToday: getLocalStorageNumber("rouletteSpinsToday", 0),
  lastRouletteSpin: getLocalStorageNumber("lastRouletteSpin", 0),
};

const levelThresholds = [
  200, 250, 300, 350, 400, 450, 500, 550, 600, 650,
  12910, 16266, 20495, 25824, 32539, 40999, 51658, 65089, 82012, 103336,
  130203, 164056, 206710, 260455, 328173, 413498, 521008, 656470, 827152, 1042211,
  1313186, 1654615, 2084814, 2626866, 3309851, 4170413, 5254720, 6620947, 8342394, 10511416,
  13244384, 16687924, 21026785, 26493749, 33382123, 42061475, 52997459, 66776798, 84138765, 106014844,
  133578704, 168309167, 212069550, 267207634, 336681618, 424218839, 534515737, 673489829, 848597184, 1069232452,
  1347232890, 1697513441, 2138866936, 2694972339, 3395665148, 4278538086, 5390957989, 6792607066, 8558684903, 10783942977,
  13587768151, 17120587871, 21571940717, 27180645304, 34247613083, 43151992484, 54371510530, 68508103268, 86320210117, 108763464748,
  137041965582, 172672876633, 217567824558, 274135458943, 345410678268, 435217454618, 548373992818, 690951230951, 870598550998, 1096954174258,
  1382162259565, 1741524447051, 2194320803285, 2764844212139, 3483703707295, 4389466671192, 5530728005702, 6968717287184, 8780583781852, 11063535565133
];

const reducer = (state, action) => {
  switch (action.type) {
    case "ADD_PLUM": {
      const newPlum = state.plums + action.payload;
      const newGP = state.gp + Math.floor(newPlum / 10000) - Math.floor(state.plums / 10000);
      return { ...state, plums: newPlum, gp: newGP };
    }

    case "BUY_AUTO_TAP":
      if (state.plums >= state.autoTapCost) {
        return {
          ...state,
          plums: state.plums - state.autoTapCost,
          autoPlums: state.autoPlums + 1,
          autoTapCost: Math.floor(state.autoTapCost * 1.5),
        };
      }
      return state;

    case "LEVEL_UP":
      return {
        ...state,
        level: state.level + 1,
        tapMultiplier: state.tapMultiplier + 0.5,
      };

    case "BUY_CRITICAL_UPGRADE":
      if (state.plums >= state.criticalUpgradeCost) {
        return {
          ...state,
          plums: state.plums - state.criticalUpgradeCost,
          criticalChance: state.criticalChance + 5,
          criticalMultiplier: state.criticalMultiplier + 0.5,
          criticalUpgradeCost: Math.floor(state.criticalUpgradeCost * 1.5),
        };
      }
      return state;

    case "START_ROULETTE": {
      const now = Date.now();
      if (state.plums < 200) return state;
      if (state.rouletteSpinsToday >= 3) return state;
      if (state.lastRouletteSpin && now - state.lastRouletteSpin < 10800000)
        return state;
      return {
        ...state,
        plums: state.plums - 200,
        rouletteSpinning: true,
        rouletteResult: null,
        rouletteSpinsToday: state.rouletteSpinsToday + 1,
        lastRouletteSpin: now,
      };
    }

    case "FINISH_ROULETTE":
      return {
        ...state,
        plums: state.plums + action.payload.bonus,
        rouletteSpinning: false,
        rouletteResult: action.payload.bonus,
      };

    case "CLEAR_ROULETTE":
      return {
        ...state,
        rouletteResult: null,
      };

    case "BUY_FINGER_UPGRADE":
      if (!state.fingerUpgradePurchased && state.plums >= action.payload.cost) {
        return {
          ...state,
          plums: state.plums - action.payload.cost,
          fingerUpgradePurchased: true,
        };
      }
      return state;

    default:
      return state;
  }
};

const GameProvider = ({ children }) => {
  const [state, dispatch] = useReducer(reducer, initialState);

  useEffect(() => {
    localStorage.setItem("plums", state.plums);
    localStorage.setItem("gp", state.gp);
    localStorage.setItem("autoPlums", state.autoPlums);
    localStorage.setItem("level", state.level);
    localStorage.setItem("tapMultiplier", state.tapMultiplier);
    localStorage.setItem("autoTapCost", state.autoTapCost);
    localStorage.setItem("criticalChance", state.criticalChance);
    localStorage.setItem("criticalMultiplier", state.criticalMultiplier);
    localStorage.setItem("criticalUpgradeCost", state.criticalUpgradeCost);
    localStorage.setItem("fingerUpgradePurchased", state.fingerUpgradePurchased);
    localStorage.setItem("rouletteSpinsToday", state.rouletteSpinsToday);
    localStorage.setItem("lastRouletteSpin", state.lastRouletteSpin);
  }, [
    state.plums,
    state.gp,
    state.autoPlums,
    state.level,
    state.tapMultiplier,
    state.autoTapCost,
    state.criticalChance,
    state.criticalMultiplier,
    state.criticalUpgradeCost,
    state.fingerUpgradePurchased,
    state.rouletteSpinsToday,
    state.lastRouletteSpin,
  ]);

  useEffect(() => {
    levelThresholds.forEach((threshold, index) => {
      if (state.plums >= threshold && state.level === index + 1) {
        dispatch({ type: "LEVEL_UP" });
      }
    });
  }, [state.plums, state.level]);

  useEffect(() => {
    const interval = setInterval(() => {
      dispatch({
        type: "ADD_PLUM",
        payload: state.autoPlums * state.tapMultiplier,
      });
    }, 1000);
    return () => clearInterval(interval);
  }, [state.autoPlums, state.tapMultiplier]);

  return (
    <GameContext.Provider value={{ state, dispatch }}>
      {children}
    </GameContext.Provider>
  );
};

export default GameProvider;
