import React, { useState, useEffect } from "react";
import { useNavigate } from "react-router-dom";

// Импорт иконок
import soundOnIcon from "./assets/icons/sound-on.png";
import soundOffIcon from "./assets/icons/sound-off.png";
import vibrationOnIcon from "./assets/icons/vibration-on.png";
import vibrationOffIcon from "./assets/icons/vibration-off.png";

const Settings = () => {
  const navigate = useNavigate();

  // Состояния для звука и вибрации
  const [isSoundEnabled, setIsSoundEnabled] = useState(true);
  const [isVibrationEnabled, setIsVibrationEnabled] = useState(true);
  // Состояние для показа модального окна подтверждения сброса
  const [showResetConfirmation, setShowResetConfirmation] = useState(false);

  // Загружаем настройки из localStorage при загрузке компонента
  useEffect(() => {
    const savedSound = localStorage.getItem("soundEnabled");
    const savedVibration = localStorage.getItem("vibrationEnabled");

    setIsSoundEnabled(savedSound !== null ? JSON.parse(savedSound) : true);
    setIsVibrationEnabled(savedVibration !== null ? JSON.parse(savedVibration) : true);
  }, []);

  // Переключение звука
  const toggleSound = () => {
    const newState = !isSoundEnabled;
    setIsSoundEnabled(newState);
    localStorage.setItem("soundEnabled", JSON.stringify(newState));
  };

  // Переключение вибрации
  const toggleVibration = () => {
    const newState = !isVibrationEnabled;
    setIsVibrationEnabled(newState);
    localStorage.setItem("vibrationEnabled", JSON.stringify(newState));
  };

  // Функция подтверждения сброса данных
  const confirmReset = () => {
    // Удаляем конкретные ключи статистики
	localStorage.removeItem("gp");
    localStorage.removeItem("plums");
    localStorage.removeItem("level");
    localStorage.removeItem("autoPlums");
    localStorage.removeItem("tapMultiplier");
    localStorage.removeItem("autoTapCost");
    localStorage.removeItem("fingerUpgradePurchased");
    localStorage.removeItem("rouletteSpinsToday");
    localStorage.removeItem("lastRouletteSpin");
    // При необходимости можно оставить или удалить настройки звука и вибрации:
    // localStorage.removeItem("soundEnabled");
    // localStorage.removeItem("vibrationEnabled");

    setShowResetConfirmation(false);
    // Перезагружаем страницу, чтобы обновить состояния приложения
    window.location.reload();
  };

  return (
    <div className="min-h-screen flex flex-col items-center justify-center bg-gray-100 p-4 relative">
      <h1 className="text-4xl font-bold mb-6 text-black">Настройки</h1>

      {/* Кнопка сброса данных игры */}
      <button
        onClick={() => setShowResetConfirmation(true)}
        className="mb-4 px-6 py-3 bg-red-600 text-white font-bold rounded-md shadow-md hover:bg-red-700 transition duration-200"
      >
        Сбросить данные игры
      </button>

      {/* Модальное окно подтверждения сброса */}
      {showResetConfirmation && (
        <div className="fixed inset-0 flex items-center justify-center bg-black bg-opacity-70 z-50">
          <div className="relative bg-gradient-to-br from-purple-900 to-pink-700 rounded-xl p-8 w-11/12 max-w-md shadow-2xl">
            <h2 className="text-3xl sm:text-4xl font-extrabold mb-4 text-yellow-300 drop-shadow-md">
              Подтверждение
            </h2>
            <p className="text-md sm:text-lg text-white mb-6">
              Вы уверены, что хотите сбросить данные игры? Все достижения и статистика будут удалены.
            </p>
            <div className="flex justify-end gap-4">
              <button
                onClick={confirmReset}
                className="px-4 py-2 bg-red-500 text-white font-bold rounded hover:bg-red-600 transition focus:outline-none"
              >
                Сбросить
              </button>
              <button
                onClick={() => setShowResetConfirmation(false)}
                className="px-4 py-2 bg-gray-300 text-black font-bold rounded hover:bg-gray-400 transition focus:outline-none"
              >
                Отмена
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Кнопка возвращения в игру */}
      <button
        onClick={() => navigate("/")}
        className="mt-6 text-lg text-black underline"
      >
        Вернуться в игру
      </button>

      {/* Нижняя панель с настройками звука и вибрации */}
      <div className="flex justify-center gap-6 mt-12">
        <button onClick={toggleSound} className="focus:outline-none">
          <img
            src={isSoundEnabled ? soundOnIcon : soundOffIcon}
            alt="Sound Toggle"
            className="w-8 h-8"
          />
        </button>

        <button onClick={toggleVibration} className="focus:outline-none">
          <img
            src={isVibrationEnabled ? vibrationOnIcon : vibrationOffIcon}
            alt="Vibration Toggle"
            className="w-8 h-8"
          />
        </button>
      </div>
    </div>
  );
};

export default Settings;
