import React, { useState } from "react";
import { useNavigate } from "react-router-dom";

const paidProducts = [
  { id: "p1", name: "Пакет 1000 Plum", price: 0.99, description: "Пополнение игрового баланса на 1000 Plum." },
  { id: "p2", name: "Премиум апгрейд", price: 4.99, description: "Увеличивает все награды в 2 раза на 1 час." },
  { id: "p3", name: "Эксклюзивный скин", price: 2.99, description: "Новый дизайн для интерфейса игры." },
];

const ArrowLeft = () => (
  <svg
    className="w-8 h-8 text-blue-200 hover:text-white transition-colors"
    fill="none"
    stroke="currentColor"
    strokeWidth="2"
    viewBox="0 0 24 24"
  >
    <path strokeLinecap="round" strokeLinejoin="round" d="M15 19l-7-7 7-7" />
  </svg>
);

const ArrowRight = () => (
  <svg
    className="w-8 h-8 text-blue-200 hover:text-white transition-colors"
    fill="none"
    stroke="currentColor"
    strokeWidth="2"
    viewBox="0 0 24 24"
  >
    <path strokeLinecap="round" strokeLinejoin="round" d="M9 5l7 7-7 7" />
  </svg>
);

const Shop = () => {
  const navigate = useNavigate();
  const [currentIndex, setCurrentIndex] = useState(0);
  // Состояния для модального окна покупки
  const [showPurchaseModal, setShowPurchaseModal] = useState(false);
  const [selectedProduct, setSelectedProduct] = useState(null);

  const handlePurchaseButtonClick = (product) => {
    setSelectedProduct(product);
    setShowPurchaseModal(true);
  };

  const handleConfirmPurchase = () => {
    alert(`Покупка "${selectedProduct.name}" за $${selectedProduct.price} пока не реализована.`);
    setShowPurchaseModal(false);
    setSelectedProduct(null);
  };

  const handleCancelPurchase = () => {
    setShowPurchaseModal(false);
    setSelectedProduct(null);
  };

  const prevItem = () => {
    setCurrentIndex((prev) => (prev === 0 ? paidProducts.length - 1 : prev - 1));
  };

  const nextItem = () => {
    setCurrentIndex((prev) => (prev === paidProducts.length - 1 ? 0 : prev + 1));
  };

  return (
    <div className="min-h-screen flex flex-col items-center justify-center bg-gradient-to-br from-green-400 to-blue-700 text-white p-6">
      <h2 className="text-4xl font-bold mb-6">МАГАЗИН</h2>

      <div className="carousel-container w-full max-w-md overflow-hidden rounded-xl bg-white bg-opacity-20 shadow-lg">
        <div
          className="carousel-track flex transition-transform duration-500 ease-in-out"
          style={{ transform: `translateX(-${currentIndex * 100}%)` }}
        >
          {paidProducts.map((product) => (
            <div
              key={product.id}
              className="carousel-item flex-shrink-0 w-full p-6 flex flex-col items-center text-white"
            >
              <h3 className="text-2xl font-semibold mb-3">{product.name}</h3>
              <p className="mb-4 text-center">{product.description}</p>
              <p className="mb-6 font-bold text-xl">${product.price.toFixed(2)}</p>
              <button
                onClick={() => handlePurchaseButtonClick(product)}
                className="w-full py-3 rounded-lg bg-yellow-500 hover:bg-yellow-600 transition-colors font-bold mb-4 text-black"
              >
                Купить за ${product.price.toFixed(2)}
              </button>
            </div>
          ))}
        </div>

        <div className="flex justify-between w-full max-w-xs mx-auto mb-4">
          <button
            onClick={prevItem}
            aria-label="Предыдущий товар"
            className="p-2 rounded-full hover:bg-blue-600 transition-colors"
          >
            <ArrowLeft />
          </button>
          <button
            onClick={nextItem}
            aria-label="Следующий товар"
            className="p-2 rounded-full hover:bg-blue-600 transition-colors"
          >
            <ArrowRight />
          </button>
        </div>
      </div>

      <button
        className="mt-10 underline text-blue-200"
        onClick={() => navigate("/")}
      >
        Вернуться в игру
      </button>

      {/* Модальное окно покупки. Стилизация по мотивам окна из Settings */}
      {showPurchaseModal && selectedProduct && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black bg-opacity-70">
          <div className="relative bg-gradient-to-br from-purple-900 to-pink-700 rounded-xl p-8 w-11/12 max-w-md shadow-2xl">
            <button
              onClick={handleCancelPurchase}
              className="absolute top-3 right-3 text-red-400 text-3xl font-bold hover:text-red-600 transition"
              aria-label="Закрыть"
            >
              &times;
            </button>
            <h2 className="text-3xl sm:text-4xl font-extrabold mb-4 text-yellow-300 drop-shadow-md">
              Подтверждение покупки
            </h2>
            <p className="text-md sm:text-lg text-white">
              Вы уверены, что хотите купить "<strong>{selectedProduct.name}</strong>" за ${selectedProduct.price.toFixed(2)}?
              <br />
              {selectedProduct.description}
            </p>
            <div className="flex justify-end gap-4 mt-6">
              <button
                onClick={handleConfirmPurchase}
                className="px-4 py-2 bg-green-500 text-white font-bold rounded hover:bg-green-600 transition"
              >
                Купить
              </button>
              <button
                onClick={handleCancelPurchase}
                className="px-4 py-2 bg-gray-300 text-black font-bold rounded hover:bg-gray-400 transition"
              >
                Отмена
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default Shop;
